import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for issue https://github.com/pinterest/ktlint/issues/2101
 * 
 * Single-line lambda with parameter should not be wrapped
 */
internal class WrappingRuleIssue2101Test {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `Given a single-line lambda with a parameter then do not report an error`() {
        val code =
            """
            val foo = { size -> icon?.getBitmap(size)?.await() }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single-line lambda with multiple parameters then do not report an error`() {
        val code =
            """
            val foo = { a, b, c -> doSomething(a, b, c) }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a lambda with parameter where the body is on the next line then do not report an error`() {
        val code =
            """
            val foo = { size ->
                icon?.getBitmap(size)?.await()
            }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a lambda passed as argument with single-line body then do not report an error`() {
        val code =
            """
            fun main() {
                items.map { size -> size.toString() }
            }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a lambda with multiline parameter list then format with proper indentation`() {
        val code =
            """
            val foo = {
                    a,
                    b,
                    c ->
                doSomething()
            }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

