            .hasLintViolations(
                LintViolation(1, 26, "Line must not end with \".\""),
                LintViolation(2, 24, "Line must not end with \".\""),
                LintViolation(3, 32, "Line must not end with \"?.\""),
            ).isFormattedAs(formattedCode)
    }

